import { Module } from '@nestjs/common';
import { CATALOG_SERVICE } from './application/interfaces/catalog-service.interface';
import { PRODUCT_REPOSITORY } from './application/interfaces/product-repository.interface';
import { CatalogService } from './application/services/catalog.service';
import { PrismaProductRepository } from './infrastructure/repositories/prisma-product.repository';
import { ProductsController } from './presentation/controllers/products.controller';

/**
 * Catalog module. Exports CATALOG_SERVICE so the Checkout module can resolve a
 * scanned barcode → product (README §2.8 Workflow 4 step 2).
 */
@Module({
  controllers: [ProductsController],
  providers: [
    CatalogService,
    { provide: CATALOG_SERVICE, useExisting: CatalogService },
    { provide: PRODUCT_REPOSITORY, useClass: PrismaProductRepository },
  ],
  exports: [CATALOG_SERVICE],
})
export class CatalogModule {}
